632:           markWord displaced = rcvr->mark().set_unlocked();
633:           mon->lock()->set_displaced_header(displaced);
634:           success = true;
635:           if (rcvr->cas_set_mark(markWord::from_pointer(mon), displaced) != displaced) {
636:             // Is it simple recursive case?
637:             if (THREAD->is_lock_owned((address) displaced.clear_lock_bits().to_pointer())) {
638:               mon->lock()->set_displaced_header(markWord::from_pointer(nullptr));
639:             } else {
640:               success = false;
641:             }
642:           }
643:         }
644:         if (!success) {
645:             CALL_VM(InterpreterRuntime::monitorenter(THREAD, mon), handle_exception);
646:         }
647: 
648:       }
649:       THREAD->set_do_not_unlock_if_synchronized(false);
650: 
651:       // Notify jvmti.
652:       // Whenever JVMTI puts a thread in interp_only_mode, method
653:       // entry/exit events are sent for that thread to track stack depth.
654:       if (JVMTI_ENABLED && THREAD->is_interp_only_mode()) {
655:         CALL_VM(InterpreterRuntime::post_method_entry(THREAD),
656:                 handle_exception);
657:       }
658: 
659:       goto run;
660:     }
661: 
662:     case popping_frame: {
663:       // returned from a java call to pop the frame, restart the call
664:       // clear the message so we don't confuse ourselves later
665:       assert(THREAD->pop_frame_in_process(), "wrong frame pop state");
666:       istate->set_msg(no_request);
667:       THREAD->clr_pop_frame_in_process();
668:       goto run;
669:     }
670: 
671:     case method_resume: {
672:       if ((istate->_stack_base - istate->_stack_limit) != istate->method()->max_stack() + 1) {
673:         // resume
674:         os::breakpoint();
675:       }
676:       // returned from a java call, continue executing.
677:       if (THREAD->has_pending_popframe() && !THREAD->pop_frame_in_process()) {
678:         goto handle_Pop_Frame;
679:       }
680:       if (THREAD->jvmti_thread_state() &&
681:           THREAD->jvmti_thread_state()->is_earlyret_pending()) {
682:         goto handle_Early_Return;
683:       }
684: 
685:       if (THREAD->has_pending_exception()) goto handle_exception;
686:       // Update the pc by the saved amount of the invoke bytecode size
687:       UPDATE_PC(istate->bcp_advance());
688:       goto run;
689:     }
690: 
691:     case deopt_resume2: {
692:       // Returned from an opcode that will reexecute. Deopt was
693:       // a result of a PopFrame request.
694:       //
695:       goto run;
696:     }
697: 
698:     case deopt_resume: {
699:       // Returned from an opcode that has completed. The stack has
700:       // the result all we need to do is skip across the bytecode
701:       // and continue (assuming there is no exception pending)
702:       //
703:       // compute continuation length
704:       //
705:       // Note: it is possible to deopt at a return_register_finalizer opcode
706:       // because this requires entering the vm to do the registering. While the
707:       // opcode is complete we can't advance because there are no more opcodes
708:       // much like trying to deopt at a poll return. In that has we simply
709:       // get out of here
710:       //
711:       if ( Bytecodes::code_at(METHOD, pc) == Bytecodes::_return_register_finalizer) {
712:         // this will do the right thing even if an exception is pending.
713:         goto handle_return;
714:       }
715:       UPDATE_PC(Bytecodes::length_at(METHOD, pc));
716:       if (THREAD->has_pending_exception()) goto handle_exception;
717:       goto run;
718:     }
719:     case got_monitors: {
720:       // continue locking now that we have a monitor to use
721:       // we expect to find newly allocated monitor at the "top" of the monitor stack.
722:       oop lockee = STACK_OBJECT(-1);
723:       VERIFY_OOP(lockee);
724:       // derefing's lockee ought to provoke implicit null check
725:       // find a free monitor
726:       BasicObjectLock* entry = (BasicObjectLock*) istate->stack_base();
727:       assert(entry->obj() == nullptr, "Frame manager didn't allocate the monitor");
728:       entry->set_obj(lockee);
729: 
730:       bool success = false;
731:       if (LockingMode == LM_LEGACY) {
732:         // Traditional fast locking.
733:         markWord displaced = lockee->mark().set_unlocked();
734:         entry->lock()->set_displaced_header(displaced);
735:         success = true;
736:         if (lockee->cas_set_mark(markWord::from_pointer(entry), displaced) != displaced) {
737:           // Is it simple recursive case?
738:           if (THREAD->is_lock_owned((address) displaced.clear_lock_bits().to_pointer())) {
739:             entry->lock()->set_displaced_header(markWord::from_pointer(nullptr));
740:           } else {
741:             success = false;
742:           }
743:         }
744:       }
745:       if (!success) {
746:         CALL_VM(InterpreterRuntime::monitorenter(THREAD, entry), handle_exception);
747:       }
748: 
749:       UPDATE_PC_AND_TOS(1, -1);
750:       goto run;
751:     }
752:     default: {
753:       fatal("Unexpected message from frame manager");
754:     }
755:   }
756: 
757: run:
758: 
759:   DO_UPDATE_INSTRUCTION_COUNT(*pc)
760:   DEBUGGER_SINGLE_STEP_NOTIFY();
761: #ifdef PREFETCH_OPCCODE
762:   opcode = *pc;  /* prefetch first opcode */
763: #endif
764: 
765: #ifndef USELABELS
766:   while (1)
767: #endif
768:   {
769: #ifndef PREFETCH_OPCCODE
770:       opcode = *pc;
771: #endif
772:       // Seems like this happens twice per opcode. At worst this is only
773:       // need at entry to the loop.
774:       // DEBUGGER_SINGLE_STEP_NOTIFY();
775:       /* Using this labels avoids double breakpoints when quickening and
776:        * when returning from transition frames.
777:        */
778:   opcode_switch:
779:       assert(istate == orig, "Corrupted istate");
780:       /* QQQ Hmm this has knowledge of direction, ought to be a stack method */
781:       assert(topOfStack >= istate->stack_limit(), "Stack overrun");
782:       assert(topOfStack < istate->stack_base(), "Stack underrun");
783: 
784: #ifdef USELABELS
785:       DISPATCH(opcode);
786: #else
787:       switch (opcode)
788: #endif
789:       {
790:       CASE(_nop):
791:           UPDATE_PC_AND_CONTINUE(1);
792: 
793:           /* Push miscellaneous constants onto the stack. */
794: 
795:       CASE(_aconst_null):
796:           SET_STACK_OBJECT(nullptr, 0);
797:           UPDATE_PC_AND_TOS_AND_CONTINUE(1, 1);
798: 
799: #undef  OPC_CONST_n
800: #define OPC_CONST_n(opcode, const_type, value)                          \
801:       CASE(opcode):                                                     \
802:           SET_STACK_ ## const_type(value, 0);                           \
803:           UPDATE_PC_AND_TOS_AND_CONTINUE(1, 1);
804: 
805:           OPC_CONST_n(_iconst_m1,   INT,       -1);
806:           OPC_CONST_n(_iconst_0,    INT,        0);
807:           OPC_CONST_n(_iconst_1,    INT,        1);
808:           OPC_CONST_n(_iconst_2,    INT,        2);
809:           OPC_CONST_n(_iconst_3,    INT,        3);
810:           OPC_CONST_n(_iconst_4,    INT,        4);
811:           OPC_CONST_n(_iconst_5,    INT,        5);
812:           OPC_CONST_n(_fconst_0,    FLOAT,      0.0);
813:           OPC_CONST_n(_fconst_1,    FLOAT,      1.0);
814:           OPC_CONST_n(_fconst_2,    FLOAT,      2.0);
815: 
816: #undef  OPC_CONST2_n
817: #define OPC_CONST2_n(opcname, value, key, kind)                         \
818:       CASE(_##opcname):                                                 \
