101: CodeletMark::~CodeletMark() {
102:   // Align so printing shows nop's instead of random code at the end (Codelets are aligned).
103:   (*_masm)->align(wordSize);
104:   // Make sure all code is in code buffer.
105:   (*_masm)->flush();
106: 
107:   // Commit Codelet.
108:   int committed_code_size = (*_masm)->code()->pure_insts_size();
109:   if (committed_code_size > 0) {
110:     // This is  the ONE place where  we pickup any assembly  remarks and debug
111:     // strings, and propagate these to the codelet.
112:     NOT_PRODUCT(_clet->use_remarks((*_masm)->code()->asm_remarks()));
113:     NOT_PRODUCT(_clet->use_strings((*_masm)->code()->dbg_strings()));
114: 
115:     AbstractInterpreter::code()->commit(committed_code_size);
116:   } else {
117:     // InterpreterCodelet is not being commited and may be re-used. We need to free the storage for
118:     // remarks and strings.
119:     NOT_PRODUCT(_clet->clear_remarks());
120:     NOT_PRODUCT(_clet->clear_strings());
121:   }
122:   // Make sure nobody can use _masm outside a CodeletMark lifespan.
123:   *_masm = nullptr;
124: }
