140: void interpreter_init_code() {
141:   Interpreter::initialize_code();
142:   // need to hit every safepoint in order to call zapping routine
143:   // register the interpreter
144:   Forte::register_stub(
145:     "Interpreter",
146:     AbstractInterpreter::code()->code_start(),
147:     AbstractInterpreter::code()->code_end()
148:   );
